import { test, expect } from '@playwright/test';

test('verify header links route correctly', async ({ page }) => {
  await page.setViewportSize({ width: 375, height: 812 });
  await page.goto('http://localhost:3002/');

  // Verify Blog link
  await page.click('header a:has-text("blog")');
  await expect(page).toHaveURL(/.*\/blog/);
  await page.goto('http://localhost:3002/');

  // Verify Portfolio link (TYPO: /portfoloi)
  const portfolioLink = await page.getAttribute('header a:has-text("portfolio")', 'href');
  expect(portfolioLink).toBe('/portfolio');
  await page.click('header a:has-text("portfolio")');
  await expect(page).toHaveURL(/.*\/portfolio/);

  // Verify Videos link
  await page.goto('http://localhost:3002/');
  await page.click('header a:has-text("videos")');
  await expect(page).toHaveURL(/.*\/videos/);

  // Verify Contact link
  await page.goto('http://localhost:3002/');
  await page.click('header a:has-text("contact")');
  await expect(page).toHaveURL(/.*\/contact/);
});
